import React, { useRef, useEffect } from 'react';
import { Link } from 'react-router-dom';
import '../styles/ContactSection.css';

const ContactSection = () => {
    const sectionRef = useRef(null);

    // Animation on scroll
    useEffect(() => {
        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.classList.add('visible');
                }
            });
        }, { threshold: 0.1 });

        if (sectionRef.current) {
            observer.observe(sectionRef.current);
        }

        return () => {
            if (sectionRef.current) {
                observer.unobserve(sectionRef.current);
            }
        };
    }, []);

    return (
        <section className="contact-section" id="contact" ref={sectionRef}>
            <div className="contact-shapes">
                <div className="contact-shape shape-1"></div>
                <div className="contact-shape shape-2"></div>
            </div>

            <div className="container">
                <div className="section-header">
                    <span className="section-badge">Get in Touch</span>
                    <h2>Contact Information</h2>
                    <p className="section-subtitle">Have questions or ready to start your tech journey? Find all the ways to reach our team below.</p>
                </div>

                <div className="contact-info-wrapper">
                    <div className="info-and-map">
                        <div className="info-card">
                            <div className="info-header">
                                <div className="info-graphic">
                                    <span className="material-icons">support_agent</span>
                                </div>
                                <h3>Contact Information</h3>
                                <p>Multiple ways to connect with our team:</p>
                            </div>

                            <div className="info-items">
                                <div className="info-item" data-type="location">
                                    <div className="info-icon-wrapper">
                                        <span className="material-icons">location_on</span>
                                    </div>
                                    <div className="info-content">
                                        <h4>Visit Us</h4>
                                        <p>3-1-5 Shibuya, Shibuya City<br />Tokyo, Japan 150-0002</p>
                                    </div>
                                </div>

                                <div className="info-item" data-type="phone">
                                    <div className="info-icon-wrapper">
                                        <span className="material-icons">phone</span>
                                    </div>
                                    <div className="info-content">
                                        <h4>Call Us</h4>
                                        <p>
                                            <a href="tel:+81312345678">+81-3-1234-5678</a> (Main)<br />
                                            <a href="tel:+81312345679">+81-3-1234-5679</a> (Admissions)
                                        </p>
                                    </div>
                                </div>

                                <div className="info-item" data-type="email">
                                    <div className="info-icon-wrapper">
                                        <span className="material-icons">email</span>
                                    </div>
                                    <div className="info-content">
                                        <h4>Email Us</h4>
                                        <p>
                                            <a href="mailto:info@forumacademy.jp">info@forumacademy.jp</a><br />
                                            <a href="mailto:admissions@forumacademy.jp">admissions@forumacademy.jp</a>
                                        </p>
                                    </div>
                                </div>

                                <div className="info-item" data-type="hours">
                                    <div className="info-icon-wrapper">
                                        <span className="material-icons">schedule</span>
                                    </div>
                                    <div className="info-content">
                                        <h4>Office Hours</h4>
                                        <p>Monday - Friday: 9AM - 6PM<br />Saturday: 10AM - 3PM</p>
                                    </div>
                                </div>
                            </div>

                            <div className="social-links">
                                <h4>Connect With Us</h4>
                                <div className="social-icons">
                                    <a href="https://twitter.com/forumacademy" className="social-icon twitter" aria-label="Twitter">
                                        <span className="material-icons">alternate_email</span>
                                    </a>
                                    <a href="https://facebook.com/forumacademy" className="social-icon facebook" aria-label="Facebook">
                                        <span className="material-icons">facebook</span>
                                    </a>
                                    <a href="https://instagram.com/forumacademy" className="social-icon instagram" aria-label="Instagram">
                                        <span className="material-icons">photo_camera</span>
                                    </a>
                                    <a href="https://linkedin.com/company/forumacademy" className="social-icon linkedin" aria-label="LinkedIn">
                                        <span className="material-icons">work</span>
                                    </a>
                                </div>
                            </div>

                            <div className="contact-cta">
                                <Link to="/contact" className="btn-full-contact">
                                    <span className="material-icons">chat</span>
                                    <span>Send us a Message</span>
                                </Link>
                            </div>
                        </div>

                        <div className="map-container">
                            <div className="map-preview">
                                <img src="/images/map-preview.jpg" alt="Map location of Forum Information Academy" />
                                <div className="map-overlay">
                                    <div className="location-pin">
                                        <span className="material-icons">place</span>
                                        <span className="pin-pulse"></span>
                                    </div>
                                </div>
                            </div>
                            <a href="https://goo.gl/maps/8F5HVCFgEZj4TPUR7" className="btn-directions" target="_blank" rel="noopener noreferrer">
                                <span className="material-icons">directions</span>
                                <span>Get Directions</span>
                            </a>
                        </div>
                    </div>
                </div>

                <div className="faq-preview">
                    <h3>Frequently Asked Questions</h3>
                    <div className="faq-items">
                        <div className="faq-item">
                            <h4>How can I schedule a campus tour?</h4>
                            <p>Campus tours are available Monday through Friday. You can schedule one by contacting our admissions office or using our online booking system.</p>
                        </div>
                        <div className="faq-item">
                            <h4>What are the application deadlines?</h4>
                            <p>Applications are accepted on a rolling basis, but we recommend applying at least 2 months before your desired start date to ensure processing time.</p>
                        </div>
                    </div>
                    <a href="/faq" className="btn-more-faq">View All FAQs</a>
                </div>
            </div>
        </section>
    );
};

export default ContactSection;
